# Graphics module: implementations, enums, and structs
from shapes import Shape, IDrawable

# Module-level constant
const PI: float = 3.14159

enum Color:
    RED = 1
    GREEN = 2
    BLUE = 3

struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

# Cross-module inheritance: Rectangle extends Shape from shapes module
class Rectangle(Shape, IDrawable):
    width: float
    height: float
    color: Color

    def __init__(self, width: float, height: float, color: Color):
        self.width = width
        self.height = height
        self.color = color

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def draw(self) -> str:
        return f"Rectangle({self.color.name})"

# Another cross-module inheritance with interface implementation
class Circle(Shape, IDrawable):
    radius: float
    center: Point

    def __init__(self, radius: float, center: Point):
        self.radius = radius
        self.center = center

    @override
    def area(self) -> float:
        return PI * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * PI * self.radius

    @override
    def draw(self) -> str:
        return f"Circle(r={self.radius})"

