# Utility module: helper functions using types from other modules
from graphics import Point, Color
from shapes import Shape, IDrawable

def describe_shape(shape: Shape) -> str:
    area: float = shape.area()
    perimeter: float = shape.perimeter()
    return f"Area: {area}, Perimeter: {perimeter}"

def create_point(x: float, y: float) -> Point:
    return Point(x, y)

def color_from_hex(hex_value: int) -> Color:
    if hex_value == 0xff0000:
        return Color.RED
    elif hex_value == 0x00ff00:
        return Color.GREEN
    else:
        return Color.BLUE
